Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Prepare insert statement
  auto insert_stmt = sqlgen::insert(records);

  // Execute the insert
  auto result = insert_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the primary key column name based on table
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Create delete statement with where condition
  auto delete_stmt = sqlgen::delete_from<table_name> 
                    | sqlgen::where(sqlgen::col<primary_key_col> == record_id);

  // Execute the delete
  auto result = delete_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const auto& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the primary key column name based on table
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Create update statement
  auto update_stmt = sqlgen::update<table_name>(
      sqlgen::col<col_name>.set(new_value)
  ) | sqlgen::where(sqlgen::col<primary_key_col> == record_id);

  // Execute the update
  auto result = update_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to `db_path` from `eas_common.hpp`

2. **Error Handling**: Properly handles connection and operation errors using the Result type pattern

3. **Dynamic Table Handling**: Uses conditional logic to determine primary key columns based on table name

4. **SQL Generation**: Leverages sqlgen's fluent API with `operator|` for building complex queries

5. **Type Safety**: Uses sqlgen's type system for column references and operations

6. **Primary Key Mapping**: Maps table names to their respective primary key columns for WHERE conditions

The implementation follows sqlgen's principles of using a fluent, type-safe API while handling the dynamic nature of table structures through conditional logic based on table names.

