```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = conn_result.value();

    // 2. Drop the Product table if it exists
    auto drop_result = (sqlgen::drop<Product> | sqlgen::if_exists)(conn);
    if (!drop_result) {
        return false;
    }

    // 3. Create the Product table
    auto create_result = conn->execute(
        "CREATE TABLE Product ("
        "product_id INTEGER PRIMARY KEY, "
        "name VARCHAR(100) NOT NULL, "
        "price REAL NOT NULL, "
        "category VARCHAR(50) NOT NULL, "
        "stock INTEGER NOT NULL DEFAULT 0)"
    );
    if (!create_result) {
        return false;
    }

    // 4. Start a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    // 5. Perform batch insertion using sqlgen::write
    auto write_result = sqlgen::write(conn, products);
    if (!write_result) {
        // 6. Rollback on failure
        conn->rollback();
        return false;
    }

    // 7. Commit the transaction on success
    auto commit_result = conn->commit();
    if (!commit_result) {
        conn->rollback();
        return false;
    }

    return true;
}

}  // namespace batch_insert_products
```

