    auto conditions = std::vector<sqlgen::Condition>();

    if (filters.title_keyword) {
        conditions.push_back("title"_c.like("%" + *filters.title_keyword + "%"));
    }

    if (filters.min_year) {
        conditions.push_back("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        conditions.push_back("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        conditions.push_back("price"_c <= *filters.max_price);
    }

    // Apply WHERE clause if any conditions were added
    if (!conditions.empty()) {
        auto combined_condition = conditions[0];
        for (size_t i = 1; i < conditions.size(); ++i) {
