    // Update from_account: balance = balance - amount
    auto update_from_result = (sqlgen::update<Account>(sqlgen::set("balance"_c = "balance"_c - amount))
                              | sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to_result = (sqlgen::update<Account>(sqlgen::set("balance"_c = "balance"_c + amount))
                            | sqlgen::where("account_id"_c == to_account_id))(conn);

    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = sqlgen::commit(conn);
    return commit_result;

  } catch (...) {
    conn->rollback();
    return false;
  }
}

